nta.declaration:
// Place global declarations here.
clock globalTime;

//R0 = (1)
clock R0;
const int R0Init = 1;
const int R0Levels = 1;

//R1 = (2)
clock R1;
const int R1Init = 1;
const int R1Levels = 1;

//R2 = (3)
clock R2;
const int R2Init = 1;
const int R2Levels = 1;

//R3 = EGF
clock R3;
const int R3Init = 15;
const int R3Levels = 15;

//R4 = ERK
clock R4;
const int R4Init = 0;
const int R4Levels = 100;

//R5 = MEK
clock R5;
const int R5Init = 0;
const int R5Levels = 60;

//R6 = NGF
clock R6;
const int R6Init = 0;
const int R6Levels = 15;

//R7 = PKC
clock R7;
const int R7Init = 0;
const int R7Levels = 40;

//R8 = RAF
clock R8;
const int R8Init = 0;
const int R8Levels = 60;

//R9 = RKIP
clock R9;
const int R9Init = 20;
const int R9Levels = 20;

//R10 = introduction of Ab
clock R10;
const int R10Init = 1;
const int R10Levels = 1;

//R11 = neutralizing antibody
clock R11;
const int R11Init = 0;
const int R11Levels = 1;

//Reaction R9 (RKIP) --| R8 (RAF)
const double k_R9_R8 = 0.006;

//Reaction R8 (RAF) --> R5 (MEK)
const double k_R8_R5 = 0.01;

//Reaction R5 (MEK) --> R4 (ERK)
const double k_R5_R4 = 0.007500000000000001;

//Reaction R11 (neutralizing antibody) --| R6 (NGF)
const double k_R11_R6 = 0.045;

//Reaction R10 (introduction of Ab) --> R11 (neutralizing antibody)
const double k_R10_R11 = 0.035;

//Reaction R3 (EGF) --> R8 (RAF)
const double k_R3_R8 = 0.008;

//Reaction R1 ((2)) --| R5 (MEK)
const double k_R1_R5 = 0.045;

//Reaction R11 (neutralizing antibody) --| R3 (EGF)
const double k_R11_R3 = 0.75;

//Reaction R2 ((3)) --| R4 (ERK)
const double k_R2_R4 = 0.045;

//Reaction R6 (NGF) --> R8 (RAF)
const double k_R6_R8 = 0.004;

//Reaction R4 (ERK) --| R5 (MEK)
const double k_R4_R5 = 0.0022500000000000003;

//Reaction R7 (PKC) --| R9 (RKIP)
const double k_R7_R9 = 0.0015;

//Reaction R6 (NGF) --> R7 (PKC)
const double k_R6_R7 = 5.333333333333334E-4;

//Reaction R4 (ERK) AND R7 (PKC) --> R8 (RAF)
const double k_R4_R7_R8 = 7.5E-5;

//Reaction R7 (PKC) --> R8 (RAF)
const double k_R7_R8 = 0.0;

//Reaction R0 ((1)) --| R8 (RAF)
const double k_R0_R8 = 0.0375;

template.declaration:
double rateR0() {
	return 0;
}

double boundedRateR0() {
	return 0;
}

double rateR1() {
	return 0;
}

double boundedRateR1() {
	return 0;
}

double rateR2() {
	return 0;
}

double boundedRateR2() {
	return 0;
}

double rateR3() {
	double R11_R3_r = k_R11_R3 * R3 * R11;
	return -R11_R3_r;
}

double boundedRateR3() {
	double r = rateR3();
	if (R3 + r > R3Levels) {
		return R3Levels - R3;
	} else if (R3 + r < 0) {
		return -R3;
	}
	return r;
}

double rateR4() {
	double R5_R4_r = k_R5_R4 * (R4Levels - R4) * R5;
	double R2_R4_r = k_R2_R4 * R4 * R2;
	return R5_R4_r - R2_R4_r;
}

double boundedRateR4() {
	double r = rateR4();
	if (R4 + r > R4Levels) {
		return R4Levels - R4;
	} else if (R4 + r < 0) {
		return -R4;
	}
	return r;
}

double rateR5() {
	double R8_R5_r = k_R8_R5 * (R5Levels - R5) * R8;
	double R1_R5_r = k_R1_R5 * R5 * R1;
	double R4_R5_r = k_R4_R5 * R5 * R4;
	return R8_R5_r - R1_R5_r - R4_R5_r;
}

double boundedRateR5() {
	double r = rateR5();
	if (R5 + r > R5Levels) {
		return R5Levels - R5;
	} else if (R5 + r < 0) {
		return -R5;
	}
	return r;
}

double rateR6() {
	double R11_R6_r = k_R11_R6 * R6 * R11;
	return -R11_R6_r;
}

double boundedRateR6() {
	double r = rateR6();
	if (R6 + r > R6Levels) {
		return R6Levels - R6;
	} else if (R6 + r < 0) {
		return -R6;
	}
	return r;
}

double rateR7() {
	double R6_R7_r = k_R6_R7 * (R7Levels - R7) * R6;
	return R6_R7_r;
}

double boundedRateR7() {
	double r = rateR7();
	if (R7 + r > R7Levels) {
		return R7Levels - R7;
	} else if (R7 + r < 0) {
		return -R7;
	}
	return r;
}

double rateR8() {
	double R9_R8_r = k_R9_R8 * R8 * R9;
	double R3_R8_r = k_R3_R8 * (R8Levels - R8) * R3;
	double R6_R8_r = k_R6_R8 * (R8Levels - R8) * R6;
	double R4_R7_R8_r = k_R4_R7_R8 * R7 * R4;
	double R7_R8_r = k_R7_R8 * R7;
	double R0_R8_r = k_R0_R8 * R8 * R0;
	return  - R9_R8_r + R3_R8_r + R6_R8_r + R4_R7_R8_r + R7_R8_r - R0_R8_r;
}

double boundedRateR8() {
	double r = rateR8();
	if (R8 + r > R8Levels) {
		return R8Levels - R8;
	} else if (R8 + r < 0) {
		return -R8;
	}
	return r;
}

double rateR9() {
	double R7_R9_r = k_R7_R9 * R9 * R7;
	return -R7_R9_r;
}

double boundedRateR9() {
	double r = rateR9();
	if (R9 + r > R9Levels) {
		return R9Levels - R9;
	} else if (R9 + r < 0) {
		return -R9;
	}
	return r;
}

double rateR10() {
	return 0;
}

double boundedRateR10() {
	return 0;
}

double rateR11() {
	double R10_R11_r = k_R10_R11 * R10;
	return R10_R11_r;
}

double boundedRateR11() {
	double r = rateR11();
	if (R11 + r > R11Levels) {
		return R11Levels - R11;
	} else if (R11 + r < 0) {
		return -R11;
	}
	return r;
}
